func Test_nativeUnixStartShell_usesQuotedDirAndPidNormalization(t *testing.T) {
	t.Parallel()
	abs := "/home/test user/.ghr/runners/my-runner-1"
	q := autostart.PosixSingleQuote(abs)
	got := nativeUnixStartShell(q)
	if !strings.Contains(got, q) {
		t.Fatalf("script should contain quoted path %q, got:\n%s", q, got)
	}
	if strings.Contains(got, "cd $HOME") {
		t.Fatalf("should not use literal cd $HOME fragment: %s", got)
	}
	if !strings.Contains(got, `tr -d '\r'`) || !strings.Contains(got, "head -n 1") {
		t.Fatalf("should normalize pid file (strip CR, first line): %s", got)
	}
	if !strings.HasPrefix(strings.TrimSpace(got), "cd ") {
		t.Fatalf("expected cd first: %s", got)
	}
}

